// cart array
let cart = [];
// selecting elements
const productContainer = document.getElementById("productContainer");
const cartContainer = document.getElementById("cartContainer");
const totalPrice = document.getElementById("totalPrice");
const cartCount = document.getElementById("cartCount");
// show products
function displayProducts() {

  productContainer.innerHTML = "";

  for (let i = 0; i < products.length; i++) {

    let product = products[i];

    let div = document.createElement("div");

    div.classList.add("card");

    div.innerHTML = `
      <img src="${product.image}" width="200">
      <h3>${product.name}</h3>
      <p>Price: ₹${product.price}</p>
      <button onclick="addToCart(${product.id})">
        Add To Cart
      </button>
    `;

    productContainer.appendChild(div);
  }
}
// add item
function addToCart(id) {

  let found = false;

  for (let i = 0; i < cart.length; i++) {

    if (cart[i].id === id) {
      cart[i].quantity = cart[i].quantity + 1;
      found = true;
    }
  }
  // if item not already in cart
  if (found === false) {

    for (let i = 0; i < products.length; i++) {

      if (products[i].id === id) {

        let item = {
          id: products[i].id,
          name: products[i].name,
          price: products[i].price,
          quantity: 1
        };

        cart.push(item);
      }
    }
  }

  saveCart();
  displayCart();
}
// display cart
function displayCart() {

  cartContainer.innerHTML = "";

  let total = 0;
  let items = 0;

  for (let i = 0; i < cart.length; i++) {

    let item = cart[i];

    total = total + (item.price * item.quantity);

    items = items + item.quantity;

    let div = document.createElement("div");

    div.classList.add("cart-item");

    div.innerHTML = `
      <h4>${item.name}</h4>
      <p>Price: ₹${item.price}</p>
      <p>Quantity: ${item.quantity}</p>

      <button onclick="increaseQty(${item.id})">+</button>

      <button onclick="decreaseQty(${item.id})">-</button>

      <button onclick="removeItem(${item.id})">
        Remove
      </button>

      <hr>
    `;

    cartContainer.appendChild(div);
  }

  totalPrice.innerText = total;

  cartCount.innerText = items;
}
// increase quantity
function increaseQty(id) {

  for (let i = 0; i < cart.length; i++) {

    if (cart[i].id === id) {
      cart[i].quantity++;
    }
  }

  saveCart();
  displayCart();
}
// decrease quantity
function decreaseQty(id) {

  for (let i = 0; i < cart.length; i++) {

    if (cart[i].id === id) {

      cart[i].quantity--;

      // remove if quantity becomes 0
      if (cart[i].quantity === 0) {
        cart.splice(i, 1);
      }
    }
  }

  saveCart();
  displayCart();
}
// remove item completely
function removeItem(id) {

  for (let i = 0; i < cart.length; i++) {

    if (cart[i].id === id) {
      cart.splice(i, 1);
    }
  }

  saveCart();
  displayCart();
}
// save cart in local storage
function saveCart() {

  localStorage.setItem("cartData", JSON.stringify(cart));
}
// load cart
function loadCart() {

  let data = localStorage.getItem("cartData");

  if (data != null) {
    cart = JSON.parse(data);
  }
}
function toggleDarkMode(){

    document.body.classList.toggle("dark");

}
// =========================
// SCROLL TO PRODUCTS
// =========================
function goToProducts() {

    document
    .getElementById("products")
    .scrollIntoView({

        behavior:"smooth"

    });
}
// search product
function searchProduct() {

  let input = document
    .getElementById("search")
    .value
    .toLowerCase();

  productContainer.innerHTML = "";

  for (let i = 0; i < products.length; i++) {

    if (products[i].name.toLowerCase().includes(input)) {

      let div = document.createElement("div");

      div.classList.add("card");

      div.innerHTML = `
        <img src="${products[i].image}" width="200">

        <h3>${products[i].name}</h3>

        <p>₹${products[i].price}</p>

        <button onclick="addToCart(${products[i].id})">
          Add To Cart
        </button>
      `;

      productContainer.appendChild(div);
    }
  }
}
// checkout
function checkout() {

  if (cart.length === 0) {
    alert("Cart is Empty");
  }
  else {
    alert("Order Placed Successfully");

    cart = [];

    saveCart();

    displayCart();
  }
}
// run when page loads
loadCart();
displayProducts();
displayCart();